#define ll long long
using namespace std;
int main()
{
    int t;
    cin >> t;
    while (t--)
    {
        ll a, b;
        cin >> a >> b;
        ll area = a * a - b * b;
        bool prime = true;
        for (int i = 2; i * i <= area; i++)
        {
            if (area % i == 0)
            {
                prime = false;
                break;
            }
        }
        if (prime)
            cout << "YES" << endl;
        else
            cout << "NO" << endl;
    }
    return 0;
}
